def load_config() -> Dict[str, Any]:
    if len(sys.argv) > 1:
        config_path = sys.argv[1]
        with open(config_path, "r", encoding="utf-8") as f:
            return json.load(f)
    return DEFAULT_CONFIG


def wait_for_kong(client: KongAdminClient, retries: int = 10, delay: int = 3) -> None:
    for attempt in range(1, retries + 1):
        try:
            client.get("/")
            return
        except Exception:
            if attempt == retries:
                raise
            time.sleep(delay)


def configure_kong(client: KongAdminClient, config: Dict[str, Any]) -> None:
    for upstream in config.get("upstreams", []):
        upstream_name = upstream["name"]
        result = client.ensure_upstream(upstream)
        print(f"Upstream configured: {upstream_name} -> {result.get('id', '')}")
        for target in upstream.get("targets", []):
            target_result = client.ensure_target(upstream_name, target)
            print(f"  Target added: {target['target']} -> {target_result.get('id', '')}")

    for service in config.get("services", []):
        service_name = service["name"]
        result = client.ensure_service(service)
        print(f"Service configured: {service_name} -> {result.get('id', '')}")
        for route in service.get("routes", []):
            route_result = client.ensure_route(service_name, route)
            print(f"  Route configured: {route['name']} -> {route_result.get('id', '')}")


